const parts = [$.input.searchQuery];
const staticTerms = "{{}} address phone hours rating reviews";
return { query: parts.filter(Boolean).join(" ") + " " + staticTerms };

const results = $.steps.searchBusinesses.response.results || [];
const topUrl = results.length > 0 ? results[0].url : '';
const searchSummary = results.map((r, i) => {
  return (i+1) + '. ' + (r.title || 'Unknown') + '\n   URL: ' + r.url + '\n   ' + (r.text || '').slice(0, 800);
}).join('\n\n');
return { topUrl, searchSummary, totalFound: results.length };

const searchData = $.steps.getTopUrl.output.searchSummary;
const scrapeResp = $.steps.scrapeTopResult.response || {};
const scrapeData = (scrapeResp.data && scrapeResp.data.markdown) ? scrapeResp.data.markdown.slice(0, 4000) : '';

const prompt = `You are a business data extraction specialist. Extract detailed business information from the following search results and scraped content.

SEARCH QUERY: ${$.input.searchQuery}

SEARCH RESULTS (${$.steps.getTopUrl.output.totalFound} businesses found):
${searchData}

DETAILED SCRAPE OF TOP RESULT:
${scrapeData}

INSTRUCTIONS:
- Extract every business identified from the search results
- For each business, find: name, address, phone, website, hours, rating, review count, category, description
- Use empty string for unavailable fields
- Deduplicate entries

Return ONLY valid JSON:
{
  "businesses": [
    {
      "name": "",
      "address": "",
      "phone": "",
      "website": "",
      "hours": "",
      "rating": "",
      "reviewCount": "",
      "category": "",
      "description": ""
    }
  ],
  "totalBusinesses": 0,
  "searchQuery": "${$.input.searchQuery}"
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { businesses: [], totalBusinesses: 0, searchQuery: $.input.searchQuery }; }

const ai = $.steps.parseAI.output;
const businesses = ai.businesses || [];
const date = new Date().toISOString().split('T')[0];
const sheetData = businesses.map((b, i) => ({
  '#': i + 1,
  'Business Name': b.name || '',
  'Address': b.address || '',
  'Phone': b.phone || '',
  'Website': b.website || '',
  'Hours': (b.hours || '').slice(0, 200),
  'Rating': b.rating || '',
  'Reviews': b.reviewCount || '',
  'Category': b.category || '',
  'Description': (b.description || '').slice(0, 200),
  'Source': 'Exa + Firecrawl',
  'Date': date
}));
return { sheetData, businessCount: businesses.length, date };
